const raw = $input.first().json;
const body = (raw.body && raw.body.action) ? raw.body : raw;
const { action, sessionId } = body;

if (!sessionId) return [{ json: { error: 'no sessionId' } }];

const store = $getWorkflowStaticData('global');
if (!store.u) store.u = {};
if (!store.u[sessionId]) store.u[sessionId] = {};

if (action === 'get') {
  const u = store.u[sessionId];
  return [{ json: {
    tasks:    u.tasks    || [],
    notes:    u.notes    || [],
    sport:    u.sport    || [],
    projects: u.projects || []
  }}];
}

if (action === 'setAll') {
  const d = body.data || {};
  const cols = ['tasks','notes','sport','projects'];
  for (const c of cols) {
    if (Array.isArray(d[c])) store.u[sessionId][c] = d[c];
  }
  return [{ json: { ok: true } }];
}

return [{ json: { error: 'unknown action' } }];
